const messages = [ 'اقرأ باسم ربك الذي خلق', 'وإذا سألك عبادي عني فإني قريب أجيب دعوة الداع إذا دعان', 'وقال ربكم ادعوني أستجب لكم', 'إن مع العسر يسرا', 'فذكر إن نفعت الذكرى' ]; document.addEventListener('DOMContentLoaded', function () { const root = document.documentElement; const saved = localStorage.getItem('theme'); if (saved) root.setAttribute('data-theme', saved); function toggleDark() { const isDark = root.getAttribute('data-theme') === 'dark'; const next = isDark ? 'light' : 'dark'; root.setAttribute('data-theme', next); localStorage.setItem('theme', next); } window.toggleDark = toggleDark; const themeBtn = document.getElementById('themeToggle'); if (themeBtn) { themeBtn.addEventListener('click', toggleDark); } document.querySelectorAll('.btn').forEach(function (btn) { btn.addEventListener('click', function () { btn.animate([ { transform: 'scale(1)' }, { transform: 'scale(0.98)' }, { transform: 'scale(1)' } ], { duration: 180, easing: 'ease-out' }); }); }); const scrollBtn = document.createElement('button'); scrollBtn.id = 'scrollTopBtn'; scrollBtn.title = 'العودة إلى الأعلى'; scrollBtn.textContent = '↑'; document.body.appendChild(scrollBtn); scrollBtn.addEventListener('click', function () { window.scrollTo({ top: 0, behavior: 'smooth' }); }); window.addEventListener('scroll', function () { if (window.scrollY > 300) { scrollBtn.classList.add('show'); } else { scrollBtn.classList.remove('show'); } }); const observer = new IntersectionObserver(function (entries, obs) { entries.forEach(function (entry) { if (entry.isIntersecting) { entry.target.classList.add('reveal'); obs.unobserve(entry.target); } }); }, { threshold: 0.1 }); document.querySelectorAll('.card').forEach(function (el) { observer.observe(el); }); if (messages && messages.length) { const msgEl = document.createElement('div'); msgEl.className = 'quran-text'; msgEl.textContent = messages[Math.floor(Math.random() * messages.length)]; document.body.prepend(msgEl); } const toggle = document.getElementById('nav-toggle'); const menu = document.querySelector('.main-nav'); if (toggle && menu) { toggle.addEventListener('click', function () { menu.classList.toggle('active'); }); } });